/**
 * Concatenate role-dashboard styles into css/dashboard-shell.css (one HTTP request).
 * Run from repo: node scripts/merge-dashboard-css.mjs (cwd: ClubMaster/src)
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const cssDir = path.join(__dirname, "..", "css");
const parts = [
  "dashboard-metal-nav.css",
  "overview-stage-photo.css",
  "role-shimmer.css",
];
const outPath = path.join(cssDir, "dashboard-shell.css");

let out =
  "/* Auto-generated by scripts/merge-dashboard-css.mjs — edit the partials, then re-run this script. */\n\n";

for (const name of parts) {
  out += `/* ========== ${name} ========== */\n`;
  out += fs.readFileSync(path.join(cssDir, name), "utf8");
  out += "\n\n";
}

fs.writeFileSync(outPath, out.replace(/\n+$/, "\n"));
console.log("Wrote", outPath);
